sql:
SELECT customer_id, AVG(equipment_spend) AS average_equipment_spend, SUM(equipment_spend) AS total_equipment_spend
FROM spending
GROUP BY customer_id;

SELECT customer_id, total_spend, equipment_spend
FROM spending
ORDER BY total_spend DESC;

